import{_ as t,C as e,o as r,c as o,a2 as i,E}from"./chunks/framework.Do_4EYrn.js";const h=JSON.parse('{"title":"安居建业 WorkBuddy 共创规范","description":"将内部经验安全抽象为通用任务方法的提交、脱敏、复现和验收规则。","frontmatter":{"title":"安居建业 WorkBuddy 共创规范","description":"将内部经验安全抽象为通用任务方法的提交、脱敏、复现和验收规则。"},"headers":[],"relativePath":"community/contributing.md","filePath":"community/contributing.md","lastUpdated":1784100816000}'),n={name:"community/contributing.md"};function d(s,a,A,c,u,B){const l=e("MermaidDiagram");return r(),o("div",null,[a[0]||(a[0]=i('<h1 id="安居建业-workbuddy-共创规范" tabindex="-1">安居建业 WorkBuddy 共创规范 <a class="header-anchor" href="#安居建业-workbuddy-共创规范" aria-label="Permalink to &quot;安居建业 WorkBuddy 共创规范&quot;">​</a></h1><p>蓝皮书公开页面只收录来源清楚、边界明确、能够复现并可验收的通用方法。内部事项先在私有范围完成来源登记和方法抽象，公开时只使用合成样例。</p><h2 id="可以提交什么" tabindex="-1">可以提交什么 <a class="header-anchor" href="#可以提交什么" aria-label="Permalink to &quot;可以提交什么&quot;">​</a></h2><ul><li>一个反复出现的办公任务和当前难点。</li><li>能复用的提示词、空白模板、检查表或 Skill 结构。</li><li>已脱敏的失败现象、原因和安全处理办法。</li><li>对现有章节的事实修正、步骤补充或过时截图提醒。</li></ul><h2 id="不要提交什么" tabindex="-1">不要提交什么 <a class="header-anchor" href="#不要提交什么" aria-label="Permalink to &quot;不要提交什么&quot;">​</a></h2><ul><li>真实项目、内部系统、部门、人员和群聊记录。</li><li>未公开经营数据、合同信息、审批意见和项目结论。</li><li>账号、密钥、本机路径和无权传播的第三方材料。</li><li>能通过名称、数字、截图或时间组合反推出具体事项的内容。</li></ul><h2 id="共创流程" tabindex="-1">共创流程 <a class="header-anchor" href="#共创流程" aria-label="Permalink to &quot;共创流程&quot;">​</a></h2>',7)),E(l,{graph:"flowchart%20LR%0A%20%20%20%20A%5B%E7%A7%81%E6%9C%89%E6%9D%A5%E6%BA%90%E7%99%BB%E8%AE%B0%5D%20--%3E%20B%5B%E6%8F%90%E7%82%BC%E9%80%9A%E7%94%A8%E6%96%B9%E6%B3%95%5D%0A%20%20%20%20B%20--%3E%20C%5B%E7%94%9F%E6%88%90%E5%90%88%E6%88%90%E6%A0%B7%E4%BE%8B%5D%0A%20%20%20%20C%20--%3E%20D%5B%E5%A4%8D%E7%8E%B0%E6%AD%A5%E9%AA%A4%E4%B8%8E%E4%BA%A7%E7%89%A9%5D%0A%20%20%20%20D%20--%3E%20E%5B%E6%A3%80%E6%9F%A5%E6%9D%83%E9%99%90%E5%92%8C%E4%BA%BA%E5%B7%A5%E7%A1%AE%E8%AE%A4%E7%82%B9%5D%0A%20%20%20%20E%20--%3E%20F%5B%E9%AA%8C%E6%94%B6%E5%90%8E%E5%85%AC%E5%BC%80%5D%0A"}),a[1]||(a[1]=i('<h2 id="统一章节结构" tabindex="-1">统一章节结构 <a class="header-anchor" href="#统一章节结构" aria-label="Permalink to &quot;统一章节结构&quot;">​</a></h2><ul><li>可应用到哪些任务</li><li>任务目标</li><li>输入材料</li><li>执行步骤</li><li>合成样例与可复制模板</li><li>人工确认点</li><li>输出物与验收标准</li><li>常见弯路</li><li>安全边界与可复用资产</li></ul><h2 id="提交共创建议" tabindex="-1">提交共创建议 <a class="header-anchor" href="#提交共创建议" aria-label="Permalink to &quot;提交共创建议&quot;">​</a></h2><p>请只描述通用任务、期望输出、当前难点、验收方式和需要人工确认的步骤。具体内部材料由有权限人员在私有范围审核，不直接进入公开页面。</p><div class="warning custom-block"><p class="custom-block-title">公开边界</p><p>通用方法不得写成公司已经正式采用的流程。外发、删除、覆盖、审批和专业判断必须保留人工确认、日志和回退要求。</p></div>',5))])}const m=t(n,[["render",d]]);export{h as __pageData,m as default};
